1	<script lang="ts">
2		import { page } from '$app/stores';
3		import { invalidateAll } from '$app/navigation';
4		import { ChevronDown, ChevronRight, Copy } from 'lucide-svelte';
5		import { createClient } from '$lib/gql/client';
6		import { gql } from 'graphql-request';
7	
8		export interface GraphIssue {
9			issueId?: string;
10			kind: string;
11			path: string | null;
12			id: string | null;
13			message: string;
14			relatedPath: string | null;
15		}
16	
17		let {
18			issues,
19			pathToDocId = {}
20		}: { issues: GraphIssue[]; pathToDocId?: Record<string, string> } = $props();
21	
22		type RepairStrategy = 'REMOVE_MISSING_DEP' | 'APPLY_SUGGESTED_ID' | 'CLEAN_PATH_MAP';
23	
24		const REPAIR_MUTATION = gql`
25			mutation GraphRepairIssue($issueId: ID!, $strategy: RepairStrategy!) {
26				graphRepairIssue(issueId: $issueId, strategy: $strategy) {
27					success
28					error
29				}
30			}
31		`;
32	
33		// Auto-repairable kinds. duplicate_id is auto-repairable only when no other
34		// document already declares a depends_on edge to the duplicate ID — the
35		// server enforces that constraint and returns an inline error otherwise.
36		const REPAIRABLE: Record<string, RepairStrategy> = {
37			missing_dep: 'REMOVE_MISSING_DEP',
38			duplicate_id: 'APPLY_SUGGESTED_ID'
39		};
40	
41		function strategyFor(issue: GraphIssue): RepairStrategy | null {
42			if (!issue.issueId) return null;
43			return REPAIRABLE[issue.kind] ?? null;
44		}
45	
46		let previewing = $state<Record<string, boolean>>({});
47		let pending = $state<Record<string, boolean>>({});
48		let inlineErrors = $state<Record<string, string>>({});
49		let previewedSuggestions = $state<Record<string, string>>({});
50	
51		const KIND_LABELS: Record<string, string> = {
52			duplicate_id: 'Duplicate ID',
53			missing_dep: 'Missing dep target',
54			id_path_missing: 'Broken id_to_path',
55			id_path_mismatch: 'id_to_path mismatch',
56			parse_error: 'Parse error',
57			required_root_missing: 'Required root missing',
58			cascade_unknown: 'Unknown cascade target',
59			cycle: 'Cycle'
60		};
61	
62		function labelFor(kind: string): string {
63			return KIND_LABELS[kind] ?? kind;
64		}
65	
66		const groups = $derived.by(() => {
67			const map = new Map<string, GraphIssue[]>();
68			for (const issue of issues) {
69				const list = map.get(issue.kind) ?? [];
70				list.push(issue);
71				map.set(issue.kind, list);
72			}
73			return Array.from(map.entries())
74				.map(([kind, list]) => ({ kind, issues: list }))
75				.sort((a, b) => labelFor(a.kind).localeCompare(labelFor(b.kind)));
76		});
77	
78		let expanded = $state<Record<string, boolean>>({});
79	
80		function toggle(kind: string) {
81			expanded[kind] = !expanded[kind];
82		}
83	
84		function docLink(path: string | null): string | null {
85			if (!path) return null;
86			const p = $page.params as Record<string, string>;
87			const nodeId = p['nodeId'];
88			const projectId = p['projectId'];
89			if (!nodeId || !projectId) return null;
90			// Use /artifacts/:artifactId when we can resolve the document ID from the path
91			const docId = pathToDocId[path];
92			if (docId) {
93				return `/nodes/${nodeId}/projects/${projectId}/artifacts/${encodeURIComponent('doc:' + docId)}`;
94			}
95			// Fall back to /documents/:path
96			const segments = path
97				.split('/')
98				.filter((s) => s.length > 0)
99				.map(encodeURIComponent)
100				.join('/');
101			return `/nodes/${nodeId}/projects/${projectId}/documents/${segments}`;
102		}
103	
104		// Deterministic mirror of cli/internal/docgraph.SuggestUniqueID; we keep a
105		// browser-side copy so the "copy unique id" button works without a
106		// round-trip. Keep in sync with the Go implementation's SHA-1 truncation.
107		async function suggestUniqueID(id: string | null, path: string | null): Promise<string> {
108			const safePath = (path ?? '').trim();
109			const safeID = (id ?? '').trim();
110			const encoder = new TextEncoder();
111			const digest = await crypto.subtle.digest('SHA-1', encoder.encode(safePath));
112			const bytes = new Uint8Array(digest);
113			const suffix = Array.from(bytes.slice(0, 4))
114				.map((b) => b.toString(16).padStart(2, '0'))
115				.join('');
116			if (safeID === '') return `doc-${suffix}`;
117			return `${safeID}-${suffix}`;
118		}
119	
120		async function copySuggestion(issue: GraphIssue, event: Event) {
121			event.stopPropagation();
122			const suggestion = await suggestUniqueID(issue.id, issue.path);
123			try {
124				await navigator.clipboard.writeText(suggestion);
125			} catch {
126				// Clipboard API unavailable (e.g. non-secure context) — surface the
127				// suggestion inline so the user can still copy it manually.
128				window.prompt('Copy suggested unique id:', suggestion);
129			}
130		}
131	
132		async function copyMessage(issue: GraphIssue, event: Event) {
133			event.stopPropagation();
134			try {
135				await navigator.clipboard.writeText(issue.message);
136			} catch {
137				window.prompt('Copy issue message:', issue.message);
138			}
139		}
140	
141		function dependencyRemovalSnippet(issue: GraphIssue): string {
142			const id = (issue.id ?? '').trim();
143			if (!id) return '';
144			return `    - ${id}`;
145		}
146	
147		async function copyDependencyRemovalSnippet(issue: GraphIssue, event: Event) {
148			event.stopPropagation();
149			const snippet = dependencyRemovalSnippet(issue);
150			if (!snippet) return;
151			try {
152				await navigator.clipboard.writeText(snippet);
153			} catch {
154				window.prompt('Copy frontmatter line to remove:', snippet);
155			}
156		}
157	
158		async function togglePreview(issue: GraphIssue) {
159			const key = issue.issueId ?? '';
160			if (!key) return;
161			const next = !previewing[key];
162			previewing[key] = next;
163			inlineErrors[key] = '';
164			if (next && issue.kind === 'duplicate_id' && !previewedSuggestions[key]) {
165				previewedSuggestions[key] = await suggestUniqueID(issue.id, issue.path);
166			}
167		}
168	
169		async function applyFix(issue: GraphIssue) {
170			const key = issue.issueId ?? '';
171			const strategy = strategyFor(issue);
172			if (!key || !strategy) return;
173			pending[key] = true;
174			inlineErrors[key] = '';
175			try {
176				const client = createClient();
177				const res = await client.request<{
178					graphRepairIssue: { success: boolean; error: string | null };
179				}>(REPAIR_MUTATION, { issueId: key, strategy });
180				if (!res.graphRepairIssue.success) {
181					inlineErrors[key] =
182						res.graphRepairIssue.error ?? 'Repair failed; use the copy-snippet fallback.';
183					return;
184				}
185				// Refresh page data so the panel and graph reflect the new state.
186				await invalidateAll();
187			} catch (err) {
188				inlineErrors[key] = err instanceof Error ? err.message : String(err);
189			} finally {
190				pending[key] = false;
191			}
192		}
193	
194		function diffRemoveDep(issue: GraphIssue): { before: string; after: string } {
195			const id = (issue.id ?? '').trim();
196			return {
197				before: `depends_on:\n  - ${id}`,
198				after: `depends_on:\n  # (entry removed)`
199			};
200		}
201	
202		function diffApplySuggestedID(issue: GraphIssue, suggested: string): { before: string; after: string } {
203			const id = (issue.id ?? '').trim();
204			return {
205				before: `id: ${id}`,
206				after: `id: ${suggested}`
207			};
208		}
209	</script>
210	
211	<section
212		data-testid="integrity-panel"
213		class="shrink-0 rounded-none border border-border-line bg-bg-surface text-sm text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-ink"
214	>
215		<header class="border-b border-border-line px-4 py-2 text-headline-md font-headline-md dark:border-dark-border-line">
216			Integrity: {issues.length}
217			{issues.length === 1 ? 'issue' : 'issues'}
218		</header>
219		<ul class="divide-y divide-border-line dark:divide-dark-border-line">
220			{#each groups as group (group.kind)}
221				{@const isOpen = expanded[group.kind] ?? false}
222				<li data-kind={group.kind}>
223					<button
224						type="button"
225						class="flex w-full items-center gap-2 px-4 py-2 text-left hover:bg-bg-canvas dark:hover:bg-dark-bg-canvas"
226						aria-expanded={isOpen}
227						data-testid={`integrity-group-${group.kind}`}
228						onclick={() => toggle(group.kind)}
229					>
230						{#if isOpen}
231							<ChevronDown class="h-4 w-4" aria-hidden="true" />
232						{:else}
233							<ChevronRight class="h-4 w-4" aria-hidden="true" />
234						{/if}
235						<span class="font-medium">{labelFor(group.kind)}</span>
236						<span class="text-fg-muted dark:text-dark-fg-muted">({group.issues.length})</span>
237					</button>
238					{#if isOpen}
239						<ul class="bg-bg-canvas px-4 pb-3 pt-1 dark:bg-dark-bg-canvas">
240							{#each group.issues as issue, idx (`${group.kind}-${idx}`)}
241								{@const repairStrategy = strategyFor(issue)}
242								{@const issueKey = issue.issueId ?? ''}
243								<li class="mt-2 flex flex-col gap-1 rounded-none bg-bg-elevated p-2 dark:bg-dark-bg-elevated">
244									<div class="flex flex-wrap items-center gap-2 font-mono text-xs">
245										{#if issue.path}
246											{@const href = docLink(issue.path)}
247											{#if href}
248												<a
249													href={href}
250													data-testid="integrity-path-link"
251													class="text-accent-lever underline hover:text-accent-lever/80 dark:text-dark-accent-lever dark:hover:text-dark-accent-lever/80"
252													>{issue.path}</a
253												>
254											{:else}
255												<span>{issue.path}</span>
256											{/if}
257										{/if}
258										{#if issue.relatedPath}
259											{@const relHref = docLink(issue.relatedPath)}
